  api.logger.info("  │  NemoClaw registered                                │");
  api.logger.info("  │                                                     │");
  api.logger.info(`  │  Endpoint:  ${bannerEndpoint.padEnd(40)}│`);
  api.logger.info(`  │  Model:     ${bannerModel.padEnd(40)}│`);
  api.logger.info("  │  Commands:  openclaw nemoclaw <command>             │");
  api.logger.info("  └─────────────────────────────────────────────────────┘");
  api.logger.info("");
}

